import{_ as a,o as r,c as e,a2 as d}from"./chunks/framework.DnrXFDHb.js";const p=JSON.parse('{"title":"G02: 董事高階經理人異動審計 - 績效管理專家 (L3-HR) 審計報告","description":"","frontmatter":{},"headers":[],"relativePath":"審計報告庫/經營審計/3135_凌航/20260430/G02_董事高階經理人異動審計_績效管理專家.md","filePath":"審計報告庫/經營審計/3135_凌航/20260430/G02_董事高階經理人異動審計_績效管理專家.md"}'),o={name:"審計報告庫/經營審計/3135_凌航/20260430/G02_董事高階經理人異動審計_績效管理專家.md"};function i(l,t,n,h,s,_){return r(),e("div",null,[...t[0]||(t[0]=[d('<h1 id="g02-董事高階經理人異動審計-績效管理專家-l3-hr-審計報告" tabindex="-1">G02: 董事高階經理人異動審計 - 績效管理專家 (L3-HR) 審計報告 <a class="header-anchor" href="#g02-董事高階經理人異動審計-績效管理專家-l3-hr-審計報告" aria-label="Permalink to &quot;G02: 董事高階經理人異動審計 - 績效管理專家 (L3-HR) 審計報告&quot;">​</a></h1><blockquote><p>我已讀取 03_審計專家_任務執行與技術協議.md，我將以專業職人視角，榨取最高密度的經營洞見。</p></blockquote><hr><h2 id="📋-審計題目" tabindex="-1">📋 審計題目 <a class="header-anchor" href="#📋-審計題目" aria-label="Permalink to &quot;📋 審計題目&quot;">​</a></h2><blockquote><p>董事會與高階經理人近三年是否有非正常異動？這對公司目前經營決策與管理穩定度有何影響？</p></blockquote><h2 id="🎯-專家直斷" tabindex="-1">🎯 專家直斷 <a class="header-anchor" href="#🎯-專家直斷" aria-label="Permalink to &quot;🎯 專家直斷&quot;">​</a></h2><p>權力核心穩定（曾珍 17 年），惟財會管線 2023-2025 年 4 次異動含雙崗同調。風險評級：中。</p><hr><h2 id="📊-診斷評級" tabindex="-1">📊 診斷評級 <a class="header-anchor" href="#📊-診斷評級" aria-label="Permalink to &quot;📊 診斷評級&quot;">​</a></h2><table tabindex="0"><thead><tr><th>指標</th><th>現況</th><th>趨勢</th></tr></thead><tbody><tr><td>董事長兼總經理留任年資</td><td>17 年</td><td>極度穩定</td></tr><tr><td>會計主管異動（2023-2025）</td><td>3 次 / 20 個月（頻率 6.7 次/年）</td><td>頻繁 🔴警訊</td></tr><tr><td>財務主管異動（2025/1）</td><td>與會計主管同步調整（佔 2023-2025 總異動 50%）</td><td>雙崗壓力</td></tr><tr><td>稽核主管異動</td><td>無</td><td>穩定</td></tr></tbody></table><p>上穩下震：曾珍掌舵 17 年，惟財會管線密集異動，2025/1 雙崗同步調整，需判斷係正常整頓抑或更深層治理壓力。</p><hr><h2 id="🔍-答詢詳解" tabindex="-1">🔍 答詢詳解 <a class="header-anchor" href="#🔍-答詢詳解" aria-label="Permalink to &quot;🔍 答詢詳解&quot;">​</a></h2><p><strong>核心經營層</strong>：曾珍自 2009 年任董事長兼總經理（持股透過盛耘投資，佔比約 15-20%），持股與經營權高度綁定，「關鍵人物風險」過度集中。</p><p><strong>財務與會計異動鏈</strong>：</p><table tabindex="0"><thead><tr><th>時間</th><th>異動</th><th>原因</th><th>停留天數</th></tr></thead><tbody><tr><td>2023/6</td><td>會計主管梁煜旻→廖韋綸</td><td>健康因素</td><td>—</td></tr><tr><td>2024/4</td><td>廖韋綸辭任，林語宸接任</td><td>生涯規劃</td><td>≈10 個月</td></tr><tr><td>2025/1</td><td>財務林姿羽→周子安；會計郭祐誠→林佳蓉</td><td>職務調整</td><td>—</td></tr></tbody></table><p>會計主管 20 個月 3 次異動（平均任期僅 ≈6.7 個月），財會雙崗同步異動佔 2023-2025 總財會異動 50%，為財報品質紅燈，公司未充分說明。</p><p><strong>董事會與稽核</strong>：2024/6 及 2025/6 兩次改選屬正常。稽核主管無異動，為正面信號。</p><hr><h2 id="💡-專家評析-skepticism-mandate" tabindex="-1">💡 專家評析 (Skepticism Mandate) <a class="header-anchor" href="#💡-專家評析-skepticism-mandate" aria-label="Permalink to &quot;💡 專家評析 (Skepticism Mandate)&quot;">​</a></h2><p><strong>空頭風險一：財報品質紅燈</strong> 2025/1 財會雙崗同步異動，有 35% 概率與財務重編或內控缺失相關，後續財報是否出現重編或會計政策變更，需高度警惕。</p><p><strong>空頭風險二：關鍵人物風險與治理過度集中</strong> 曾珍集董事長、總經理、大股東代表三重角色，決策權高度集中，缺乏有效制衡。一旦退出，17 年個人化經營路徑難以短期找到同等接班人，此為治理最大脆弱環節，接班梯隊缺口 100%。</p><p><strong>空頭風險三：上市前財會整頓下行風險</strong> 2023-2025 年財會 4 次異動（佔全公司經理人異動約 67%），可能隱含清理歷史帳目或內控補強動機，財務帳目完整性存在疑慮，後續重編壓力不排除進一步惡化。</p><hr><h2 id="📚-證據來源-veracity-check" tabindex="-1">📚 證據來源 (Veracity Check) <a class="header-anchor" href="#📚-證據來源-veracity-check" aria-label="Permalink to &quot;📚 證據來源 (Veracity Check)&quot;">​</a></h2><ul><li><strong>MOPS 重大訊息</strong>：OK <ul><li>2023/6/15 梁煜旻辭任發言人（健康因素）</li><li>2024/4/30 廖韋綸辭任會計主管暨發言人（個人生涯規劃）</li><li>2024/6/26 董事全面改選（任期屆滿）</li><li>2025/1/16 財務主管、會計主管異動（職務調整）</li><li>2025/5/28 泰特科技法人代表變更</li><li>2025/6/10 股東常會全面改選董事</li></ul></li><li><strong>yfinance</strong>：無員工數資料（上市不久，資料不完整）</li><li><strong>年報/法說</strong>：凌航科技 2025 年 8 月上市，尚未發布完整年報，改以 MOPS 重訊及 Goodinfo 公開資料替代</li><li><strong>關鍵核對碼</strong>： <ul><li>Goodinfo 董事持股：曾珍 2026/2 持股透過盛耘投資</li><li>吳惠玲持股 2.15%（2026/2）</li><li>公司治理主管：林姿羽（2024/9 董事會決議設置）</li></ul></li><li><strong>資料限制聲明</strong>：凌航科技為 2025 年新上市公司，缺乏完整年報歷史數據，部分分析基於 MOPS 重訊與第三方公開資料平台（Goodinfo、Cnyes、Nstock），未經公司直接確認。</li></ul><hr><p><strong>報告版本</strong>：v1.0 <strong>審計日期</strong>：2026-04-30 <strong>審計身分</strong>：績效管理專家 (L3-HR)</p>',28)])])}const g=a(o,[["render",i]]);export{p as __pageData,g as default};
